def test_anthropic_pass_through_route_binds_public_proxy_handler():
    from litellm.proxy.pass_through_endpoints import llm_passthrough_endpoints as module

    endpoints = [
        getattr(route.endpoint, "__name__", None)
        for route in module.router.routes
        if getattr(route, "path", None) == "/anthropic/{endpoint:path}"
    ]

    assert endpoints == ["anthropic_proxy_route"]


def _build_claude_code_agent_project_request_body(model: str) -> dict[str, Any]:
    return {
        "model": model,
        "max_tokens": 32,
        "litellm_metadata": {
            "tags": ["existing-tag"],
            "trace_name": "claude-code",
        },
        "messages": [
            {
                "role": "user",
                "content": _CLAUDE_CODE_AGENT_PROJECT_TEXT,
            }
        ],
    }


async def _prepare_claude_code_agent_project_request_body(
    model: str,
    *,
    headers: dict[str, str] | None = None,
) -> dict[str, Any]:
    mock_request = MagicMock(spec=Request)
    mock_request.headers = headers or {}
    request_body = _build_claude_code_agent_project_request_body(model)
    updated_body, _, _, _ = await _prepare_anthropic_request_body_for_passthrough(
        mock_request,
        request_body,
    )
    return updated_body


@pytest.mark.asyncio
async def test_prepare_anthropic_request_body_rejects_tool_result_without_tool_use_id():
    mock_request = MagicMock(spec=Request)
    mock_request.headers = {}
    request_body = {
        "model": "claude-opus-4-6",
        "max_tokens": 32,
        "messages": [
            {
                "role": "assistant",
                "content": [{"type": "tool_result", "content": "42"}],
            }
        ],
    }

    with pytest.raises(HTTPException) as exc_info:
        await _prepare_anthropic_request_body_for_passthrough(
            mock_request,
            request_body,
        )

    assert exc_info.value.status_code == 400
    assert "tool_result.tool_use_id" in str(exc_info.value.detail)


@pytest.mark.asyncio
@pytest.mark.parametrize("tool_use_id", [None, "", "   "])
async def test_prepare_anthropic_request_body_repairs_tool_use_without_id(
    tool_use_id,
):
    mock_request = MagicMock(spec=Request)
    mock_request.headers = {}
    tool_use_block = {
        "type": "tool_use",
        "name": "Read",
        "input": {"file_path": "/tmp/a.txt"},
    }
    if tool_use_id is not None:
        tool_use_block["id"] = tool_use_id
    request_body = {
        "model": "claude-opus-4-6",
        "max_tokens": 32,
        "messages": [
            {"role": "user", "content": "Read a file."},
            {
                "role": "assistant",
                "content": [
                    {"type": "text", "text": "I will read it."},
                    tool_use_block,
                ],
            },
        ],
    }

    updated_body, _, _, _ = await _prepare_anthropic_request_body_for_passthrough(
        mock_request,
        request_body,
    )

    repaired_id = updated_body["messages"][1]["content"][1]["id"]
    assert isinstance(repaired_id, str)
    assert repaired_id.startswith("call_")
    assert updated_body["litellm_metadata"][
        "anthropic_tool_use_id_repaired_count"
    ] == 1


