@pytest.mark.asyncio
async def test_prepare_anthropic_request_body_preserves_tool_use_id_in_history():
    mock_request = MagicMock(spec=Request)
    mock_request.headers = {}
    tool_use_block = {
        "type": "tool_use",
        "id": "toolu_read_1",
        "name": "Read",
        "input": {"file_path": "/tmp/a.txt"},
    }
    tool_result_block = {
        "type": "tool_result",
        "tool_use_id": "toolu_read_1",
        "content": "alpha",
    }
    request_body = {
        "model": "claude-opus-4-6",
        "max_tokens": 32,
        "messages": [
            {"role": "user", "content": "Read a file."},
            {
                "role": "assistant",
                "content": [
                    {"type": "text", "text": "I will read it."},
                    tool_use_block,
                ],
            },
            {"role": "user", "content": [tool_result_block]},
        ],
    }

    updated_body, _, _, _ = await _prepare_anthropic_request_body_for_passthrough(
        mock_request,
        request_body,
    )

    assert updated_body["messages"][1]["content"][1]["id"] == "toolu_read_1"
