    @pytest.mark.asyncio
    async def test_build_passthrough_logging_input_serializes_body_once(self):
        from litellm.proxy.pass_through_endpoints import pass_through_endpoints as pte

        parsed_body = {"model": "gpt-5.4", "messages": [{"role": "user", "content": "hi"}]}
        call_count = {"count": 0}
        original_safe_dumps = pte.safe_dumps

        def counting_safe_dumps(value):
            if value is parsed_body:
                call_count["count"] += 1
            return original_safe_dumps(value)

        with patch.object(pte, "safe_dumps", side_effect=counting_safe_dumps):
            envelope = pte._build_passthrough_logging_input(parsed_body)

        assert call_count["count"] == 1
        assert envelope == [
            {"role": "user", "content": original_safe_dumps(parsed_body)}
        ]

    @pytest.mark.asyncio
    async def test_build_passthrough_request_observability_envelope_preserves_body_reference(
        self,
    ):
        from litellm.proxy.pass_through_endpoints import pass_through_endpoints as pte

        parsed_body = {
            "model": "gpt-5.4",
            "messages": [{"role": "user", "content": "hi"}],
            "tools": [
                {
                    "type": "function",
                    "function": {"name": "spawn_agent", "parameters": {"type": "object"}},
                }
            ],
            "litellm_metadata": {
                "session_id": "session-abc",
                "repository": "/home/zepfu/projects/litellm",
                "requested_model_alias": "aawm-code",
                "passthrough_route_family": "codex_responses",
            },
        }
        original_keys = set(parsed_body)
        call_count = {"count": 0}
        original_safe_dumps = pte.safe_dumps

        def counting_safe_dumps(value):
            if value is parsed_body:
                call_count["count"] += 1
            return original_safe_dumps(value)

        with patch.object(pte, "safe_dumps", side_effect=counting_safe_dumps):
            envelope = pte._build_passthrough_request_observability_envelope(
                parsed_body
            )

        assert call_count["count"] == 1
        assert envelope.parsed_body is parsed_body
        assert envelope.complete_input_dict is parsed_body
        assert envelope.logging_input == [
            {"role": "user", "content": envelope.serialized_body}
        ]
        assert set(parsed_body) == original_keys

        parsed_body["model"] = "mutated"
        assert envelope.parsed_body["model"] == "mutated"
        assert envelope.complete_input_dict["model"] == "mutated"

    def test_copy_custom_body_for_passthrough_uses_shallow_copy(self):
        from litellm.proxy.pass_through_endpoints import pass_through_endpoints as pte

        custom_body = {
            "model": "gpt-5.4",
            "messages": [{"role": "user", "content": "hi"}],
            "tools": [{"type": "function", "function": {"name": "spawn_agent"}}],
        }
        copied = pte._copy_custom_body_for_passthrough(custom_body)

        assert copied is not custom_body
        assert copied["messages"] is custom_body["messages"]
        assert copied["tools"] is custom_body["tools"]
        copied["model"] = "mutated"
        assert custom_body["model"] == "gpt-5.4"

    def test_detach_passthrough_body_for_kwargs_preserves_provider_reference(self):
        from litellm.proxy.pass_through_endpoints import pass_through_endpoints as pte

        parsed_body = {
            "model": "gpt-5.4",
            "messages": [{"role": "user", "content": "hi"}],
            "litellm_metadata": {"session_id": "session-abc"},
            "litellm_logging_obj": object(),
        }
        working_body, provider_body = pte._detach_passthrough_body_for_kwargs(parsed_body)

        assert working_body is not parsed_body
        assert provider_body is parsed_body
        assert working_body["messages"] is parsed_body["messages"]
        assert "litellm_metadata" in working_body
        assert "litellm_logging_obj" in working_body
        assert parsed_body["litellm_metadata"]["session_id"] == "session-abc"

