    @pytest.mark.asyncio
    async def test_codex_opencode_zen_stream_injects_responses_item_lifecycle(
        self,
    ):
        mock_request = MagicMock(spec=Request)
        mock_request.method = "POST"
        mock_request.headers = {
            "content-type": "application/json",
            "originator": "codex_cli_rs",
            "user-agent": "codex_cli_rs/0.0.0",
            "session_id": "codex-opencode-stream-session",
        }
        mock_request.url = httpx.URL(
            "http://127.0.0.1:4001/openai_passthrough/v1/responses"
        )
        mock_request.scope = {
            "path": "/openai_passthrough/v1/responses",
            "query_string": b"",
        }
        mock_request.query_params = {}

        class _FakeResponseEvent(SimpleNamespace):
            def model_dump_json(self, exclude_none=True):
                _ = exclude_none
                return json.dumps(self.__dict__)

        async def _responses_events():
            yield _FakeResponseEvent(
                type="response.output_text.delta",
                delta="OPENCODE CODEX OK",
            )

        fake_stream_wrapper = object()
        iterator_inits = []

        class _FakeCompletionStreamingIterator:
            def __init__(self, **kwargs):
                iterator_inits.append(kwargs)

            def __aiter__(self):
                return _responses_events()

        prepared_body = {
            "model": "opencode/deepseek-v4-flash",
            "input": "just a stream test msg",
            "stream": True,
        }

        with patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._load_local_opencode_zen_api_key",
            new=AsyncMock(return_value="opencode-test-key"),
        ), patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints.HttpPassThroughEndpointHelpers.validate_outgoing_egress"
        ) as mock_validate_egress, patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints.litellm.acompletion",
            new=AsyncMock(return_value=fake_stream_wrapper),
        ) as mock_acompletion, patch(
            "litellm.responses.litellm_completion_transformation.streaming_iterator.LiteLLMCompletionStreamingIterator",
            _FakeCompletionStreamingIterator,
        ):
            response = await _handle_codex_opencode_zen_adapter_route(
                endpoint="v1/responses",
                request=mock_request,
                fastapi_response=MagicMock(spec=Response),
                user_api_key_dict=MagicMock(),
                prepared_request_body=prepared_body,
                adapter_model="deepseek-v4-flash",
            )

        mock_validate_egress.assert_called_once()
        assert mock_validate_egress.call_args.kwargs["url"] == (
            "https://opencode.ai/zen/v1/chat/completions"
        )
        call_kwargs = mock_acompletion.await_args.kwargs
        assert call_kwargs["model"] == "deepseek-v4-flash"
        assert call_kwargs["api_key"] == "opencode-test-key"
        assert call_kwargs["api_base"] == "https://opencode.ai/zen/v1"
        assert call_kwargs["stream"] is True
        assert call_kwargs["custom_llm_provider"] == "openai"
        assert iterator_inits[0]["litellm_custom_stream_wrapper"] is fake_stream_wrapper
        assert iterator_inits[0]["model"] == "deepseek-v4-flash"
        assert iterator_inits[0]["custom_llm_provider"] == "openai"
        assert isinstance(response, StreamingResponse)
        chunks = [chunk async for chunk in response.body_iterator]
        payload = "".join(
            chunk.decode("utf-8") if isinstance(chunk, bytes) else str(chunk)
            for chunk in chunks
        )
        assert "event: response.output_text.delta" in payload
        assert '"OPENCODE CODEX OK"' in payload
        assert payload.rstrip().endswith("data: [DONE]")

    @pytest.mark.asyncio
    async def test_anthropic_opencode_zen_route_translates_to_responses_passthrough(
        self,
    ):
        mock_request = MagicMock(spec=Request)
        mock_request.method = "POST"
        mock_request.headers = {
            "content-type": "application/json",
            "x-api-key": "claude-client-key",
            "session_id": "claude-opencode-session",
        }
        mock_request.url = httpx.URL("http://127.0.0.1:4001/anthropic/v1/messages")
        mock_request.scope = {
            "path": "/anthropic/v1/messages",
            "query_string": b"",
        }
        mock_request.query_params = {}
        prepared_body = {
            "model": "opencode-zen/qwen3.6-plus-free",
            "messages": [{"role": "user", "content": "hello"}],
            "max_tokens": 32,
            "stream": False,
        }
        translated_body = {
            "model": "qwen3.6-plus-free",
            "input": "hello",
            "stream": False,
            "litellm_metadata": {
                "client_name": "claude-cli",
                "passthrough_route_family": (
                    "anthropic_opencode_zen_responses_adapter"
                ),
                "tags": ["route:anthropic_opencode_zen_responses_adapter"],
            },
        }
        translated_response = Response(
            content=json.dumps(
                {
                    "id": "msg_opencode",
                    "type": "message",
                    "role": "assistant",
                    "model": "qwen3.6-plus-free",
                    "content": [{"type": "text", "text": "ok"}],
                }
            ),
            media_type="application/json",
        )

        with patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._build_anthropic_responses_adapter_request_body",
            return_value=dict(translated_body),
        ), patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._load_local_opencode_zen_api_key",
            new=AsyncMock(return_value="opencode-test-key"),
        ), patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints.pass_through_request",
            new=AsyncMock(
                return_value=Response(
                    content=json.dumps(
                        {
                            "id": "resp_opencode",
                            "object": "response",
                            "model": "qwen3.6-plus-free",
                            "output": [
                                {
                                    "type": "message",
                                    "role": "assistant",
                                    "content": [
                                        {"type": "output_text", "text": "ok"}
                                    ],
                                }
                            ],
                        }
                    ),
                    media_type="application/json",
                )
            ),
        ) as mock_pass_through_request, patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._build_anthropic_response_from_responses_response",
            return_value=translated_response,
        ):
            response = await _handle_anthropic_opencode_zen_responses_adapter_route(
                endpoint="v1/messages",
                request=mock_request,
                fastapi_response=MagicMock(spec=Response),
                user_api_key_dict=MagicMock(),
                prepared_request_body=prepared_body,
                adapter_model="qwen3.6-plus-free",
            )

        call_kwargs = mock_pass_through_request.await_args.kwargs
        assert call_kwargs["target"] == "https://opencode.ai/zen/v1/responses"
        assert call_kwargs["custom_headers"]["authorization"] == (
            "Bearer opencode-test-key"
        )
        assert call_kwargs["custom_llm_provider"] == "opencode_zen"
        assert call_kwargs["egress_credential_family"] == "opencode"
        assert call_kwargs["expected_target_family"] == "opencode"
        litellm_metadata = call_kwargs["custom_body"]["litellm_metadata"]
        assert (
            litellm_metadata["passthrough_route_family"]
            == "anthropic_opencode_zen_responses_adapter"
        )
        assert litellm_metadata["opencode_zen"] is True
        assert litellm_metadata["opencode_zen_adapter_model"] == (
            "qwen3.6-plus-free"
        )
        assert litellm_metadata["client_name"] == "claude-cli"
        assert response.body == translated_response.body

    @pytest.mark.asyncio
    async def test_codex_google_code_assist_auto_probe_empty_success_raises_before_logging(
        self,
    ):
        from litellm.proxy.pass_through_endpoints import llm_passthrough_endpoints as module

        mock_request = MagicMock(spec=Request)
        mock_request.method = "POST"
        mock_request.headers = {
            "content-type": "application/json",
            "originator": "codex_cli_rs",
            "user-agent": "codex_cli_rs/0.0.0",
            "session_id": "codex-session",
        }
        mock_request.url = httpx.URL(
            "http://127.0.0.1:4001/openai_passthrough/v1/responses"
        )
        mock_request.scope = {
            "path": "/openai_passthrough/v1/responses",
            "query_string": b"",
        }
        mock_request.query_params = {}
        adapter_request = SimpleNamespace(
            annotated_target_url=httpx.URL(
                "https://cloudcode-pa.googleapis.com/v1internal:streamGenerateContent"
            ),
            adapter_headers={},
            custom_llm_provider="gemini",
            google_adapter_rate_limit_key="google-lane",
            target_url="https://cloudcode-pa.googleapis.com/v1internal:streamGenerateContent",
            wrapped_request_body={"request": {"contents": []}},
            target_query_params={"alt": "sse"},
            is_stream=True,
            client_requested_stream=False,
            google_model="gemini-3.1-flash-lite-preview",
            completion_messages=[{"role": "user", "content": "hello"}],
            gemini_optional_params={},
            tool_name_mapping={},
            codex_request_input="hello",
            responses_api_request={"model": "gemini-3.1-flash-lite-preview"},
        )
        empty_model_response = SimpleNamespace(
            id="chatcmpl-empty-gemini",
            model="gemini-3.1-flash-lite-preview",
            choices=[
                SimpleNamespace(
                    message=SimpleNamespace(
                        content=None,
                        tool_calls=None,
                        function_call=None,
                    )
                )
            ],
            usage=SimpleNamespace(
                prompt_tokens=10,
                completion_tokens=0,
                total_tokens=10,
            ),
        )

        with patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints.HttpPassThroughEndpointHelpers.validate_outgoing_egress"
        ), patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._perform_google_adapter_pass_through_request",
            new=AsyncMock(
                return_value=StreamingResponse(
                    iter([b"data: [DONE]\n\n"]),
                    media_type="text/event-stream",
                )
            ),
        ), patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._collect_google_code_assist_model_response_from_stream",
            new=AsyncMock(return_value=empty_model_response),
        ), patch(
            "litellm.responses.litellm_completion_transformation.transformation.LiteLLMCompletionResponsesConfig.transform_chat_completion_response_to_responses_api_response",
            return_value={"id": "should-not-log"},
        ) as mock_transform:
            with pytest.raises(ProxyException) as exc_info:
                await module._perform_codex_google_code_assist_adapter_request(
                    request=mock_request,
                    user_api_key_dict=MagicMock(),
                    adapter_request=adapter_request,
                    use_alias_candidate_probe=True,
                )

        assert exc_info.value.detail["error"]["code"] == (
            "aawm_codex_auto_agent_empty_success"
        )
        assert exc_info.value.detail["error"]["status"] == "RATE_LIMIT_EXCEEDED"
        assert exc_info.value.detail["diagnostic"]["context"]["adapter"] == (
            "codex_auto_agent_google_code_assist"
        )
        mock_transform.assert_not_called()

