def test_codex_auto_agent_alias_metadata_uses_requested_alias():
    request = _build_codex_auto_agent_request()
    body = {
        "model": "aawm-low",
        "litellm_metadata": {"session_id": "codex-session"},
    }
    updated_body = _add_codex_auto_agent_alias_metadata(
        body,
        request=request,
        selection={
            "candidate": {
                "provider": "opencode_zen",
                "model": "deepseek-v4-flash",
                "route_family": "codex_opencode_zen_adapter",
                "last_resort": False,
            },
            "selection_reason": "first_available",
            "lane_key": "opencode_zen",
            "skipped": [
                {
                    "provider": "opencode_zen",
                    "model": "big-pickle",
                    "route_family": "codex_opencode_zen_adapter",
                    "last_resort": False,
                    "lane_key": "opencode_zen",
                    "cooldown_seconds": 60.0,
                    "reason": "cooldown",
                }
            ],
        },
        attempts=[
            {
                "provider": "opencode_zen",
                "model": "deepseek-v4-flash",
                "route_family": "codex_opencode_zen_adapter",
                "last_resort": False,
                "lane_key": "opencode_zen",
                "reason": "first_available",
            }
        ],
    )

    metadata = updated_body["litellm_metadata"]
    assert metadata["model_alias_label"] == "aawm-low"
    assert metadata["requested_model_alias"] == "aawm-low"
    assert metadata["codex_auto_agent_alias"] == "aawm-low"
    assert metadata["codex_auto_agent_selected_provider"] == "opencode_zen"
    assert metadata["codex_auto_agent_selected_model"] == "deepseek-v4-flash"
    assert metadata["codex_auto_agent_selected_route_family"] == (
        "codex_opencode_zen_adapter"
    )
    assert metadata["codex_auto_agent_selection_reason"] == "first_available"
    assert metadata["codex_auto_agent_lane_key"] == "opencode_zen"
    assert metadata["codex_auto_agent_attempts"][0]["provider"] == "opencode_zen"
    assert metadata["codex_auto_agent_skipped_candidates"][0]["provider"] == (
        "opencode_zen"
    )
    audit_events = metadata["aawm_alias_routing_audit_events"]
    assert [event["event_type"] for event in audit_events] == [
        "candidate_skipped_cooldown",
        "candidate_selected",
    ]
    skipped_event = audit_events[0]
    assert skipped_event["alias_model"] == "aawm-low"
    assert skipped_event["provider"] == "opencode_zen"
    assert skipped_event["model"] == "big-pickle"
    assert skipped_event["cooldown_key"] == (
        "opencode_zen:big-pickle:opencode_zen"
    )
    assert skipped_event["cooldown_seconds"] == 60.0
    assert skipped_event["skipped"] is True
    assert "codex-auto-agent-alias:aawm-low" in metadata["tags"]
    assert "model-alias:aawm-low" in metadata["tags"]


@pytest.mark.asyncio
async def test_codex_auto_agent_alias_code_falls_back_to_composer_after_spark_429(
    monkeypatch,
):
    request = _build_codex_auto_agent_request()
    body = {
        "model": "aawm-code",
        "input": "hello",
        "stream": False,
        "litellm_metadata": {"session_id": "codex-session"},
    }
    spark_error = ProxyException(
        message="spark quota exhausted",
        type="rate_limit_error",
        param="model",
        code=429,
    )
    spark_error.detail = {
        "error": {
            "message": "usage_limit_reached",
            "code": 429,
            "status": "RESOURCE_EXHAUSTED",
        }
    }
    composer_success = Response(content='{"ok": true}', media_type="application/json")

    with patch(
        "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints.pass_through_request",
        new=AsyncMock(side_effect=spark_error),
    ) as mock_pass_through:
        with patch(
            "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._perform_codex_auto_agent_grok_native_responses_request",
            new=AsyncMock(return_value=composer_success),
        ) as mock_composer:
            response = await _handle_codex_auto_agent_alias_route(
                endpoint="/v1/responses",
                request=request,
                fastapi_response=MagicMock(spec=Response),
                user_api_key_dict=MagicMock(),
                prepared_request_body=body,
                target_url="https://chatgpt.com/backend-api/codex/responses",
                api_key=None,
                forward_headers=True,
            )

    assert response is composer_success
    mock_pass_through.assert_awaited_once()
    mock_composer.assert_awaited_once()
    assert mock_composer.await_args.kwargs["request_body"]["model"] == (
        "grok-composer-2.5-fast"
    )
    composer_body = mock_composer.await_args.kwargs["request_body"]
    metadata = composer_body["litellm_metadata"]
    assert metadata["requested_model_alias"] == "aawm-code"
    assert metadata["codex_auto_agent_alias"] == "aawm-code"
    assert metadata["codex_auto_agent_selected_provider"] == "xai"
    assert metadata["codex_auto_agent_selected_model"] == "grok-composer-2.5-fast"
    assert metadata["codex_auto_agent_selected_route_family"] == (
        "codex_grok_native_responses_adapter"
    )
    assert metadata["codex_auto_agent_attempts"][0]["status"] == "cooldown_set"
    assert metadata["codex_auto_agent_skipped_candidates"][0]["provider"] == "openai"
    assert [attempt["model"] for attempt in metadata["codex_auto_agent_attempts"]] == [
        "gpt-5.3-codex-spark",
        "grok-composer-2.5-fast",
    ]
    audit_events = metadata["aawm_alias_routing_audit_events"]
    retryable_index = next(
        index
        for index, event in enumerate(audit_events)
        if event["event_type"] == "candidate_retryable_failure"
    )
    selected_index = next(
        index
        for index, event in enumerate(audit_events)
        if event["event_type"] == "candidate_selected"
    )
    assert retryable_index < selected_index
    retryable_event = audit_events[retryable_index]
    assert retryable_event["provider"] == "openai"
    assert retryable_event["model"] == "gpt-5.3-codex-spark"
    assert retryable_event["failure_class"]
    selected_event = audit_events[selected_index]
    assert selected_event["provider"] == "xai"
    assert selected_event["model"] == "grok-composer-2.5-fast"


@pytest.mark.parametrize(
    ("message", "expected_token"),
    [
        (
            "We're currently experiencing high demand, which may cause temporary errors.",
            "HIGH_DEMAND",
        ),
        (
            "Selected model is at capacity. Please try a different model.",
            "MODEL_AT_CAPACITY",
        ),
    ],
)
def test_codex_auto_agent_retryable_exhaustion_classifies_capacity_text(
    message,
    expected_token,
):
    exc = RuntimeError(message)

    assert _classify_codex_auto_agent_retryable_exhaustion(exc) == (
        "capacity_exhausted"
    )
    assert expected_token in _extract_codex_auto_agent_error_tokens(exc)


def test_codex_auto_agent_retryable_exhaustion_ignores_tool_shape_text():
    exc = RuntimeError("Invalid tool schema: missing required property name.")

    assert _classify_codex_auto_agent_retryable_exhaustion(exc) is None
    assert _extract_codex_auto_agent_error_tokens(exc) == set()


def test_codex_auto_agent_retryable_exhaustion_classifies_deepseek_tool_mismatch():
    exc = RuntimeError(
        "Error from provider (DeepSeek): An assistant message with 'tool_calls' "
        "must be followed by tool messages responding to each 'tool_call_id'. "
        "(insufficient tool messages following tool_calls message)"
    )

    assert _classify_codex_auto_agent_retryable_exhaustion(exc) == (
        "provider_format_rejected"
    )
    assert "DEEPSEEK_TOOL_MESSAGE_MISMATCH" in _extract_codex_auto_agent_error_tokens(
        exc
    )


