def test_auto_agent_alias_route_event_records_zero_turn_rollup(monkeypatch):
    from litellm.proxy.pass_through_endpoints import llm_passthrough_endpoints as endpoints

    rollups = []
    monkeypatch.setattr(endpoints, "emit_aawm_route_status_event", lambda **kwargs: None)
    monkeypatch.setattr(
        endpoints,
        "record_aawm_route_rollup",
        lambda **kwargs: rollups.append(kwargs),
    )
    monkeypatch.setattr(endpoints.verbose_proxy_logger, "warning", lambda message: None)

    endpoints._emit_auto_agent_alias_route_event(
        {
            "event_type": "candidate_retryable_failure",
            "candidate_status": "cooldown_set",
            "failure_class": "capacity_exhausted",
            "alias_model": "aawm-low",
            "model": "grok-composer-2.5-fast",
            "rollup_group_header_label": "litellm@Codex[0.141.0]",
            "incoming_endpoint": "/openai_passthrough/responses",
            "outgoing_target": "grok_cli_chat_proxy",
        },
        level="warning",
    )

    assert rollups == [
        {
            "group_header_label": "litellm@Codex[0.141.0]",
            "incoming_endpoint": "/openai_passthrough/responses",
            "outgoing_target": "grok_cli_chat_proxy",
            "model_label": "grok-composer-2.5-fast(aawm-low)",
            "turns": 0,
            "status": "Cooling Down",
        }
    ]


@pytest.mark.asyncio
async def test_codex_read_agent_alias_falls_back_after_high_demand(monkeypatch):
    request = _build_codex_auto_agent_request()
    body = {
        "model": "aawm-read",
        "input": "hello",
        "stream": False,
        "litellm_metadata": {"session_id": "codex-session"},
    }
    spark_error = RuntimeError(
        "We're currently experiencing high demand, which may cause temporary errors."
    )
    deepseek_success = Response(content='{"ok": true}', media_type="application/json")

    with patch(
        "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints.pass_through_request",
        new=AsyncMock(side_effect=spark_error),
    ) as mock_pass_through, patch(
        "litellm.proxy.pass_through_endpoints.llm_passthrough_endpoints._perform_codex_auto_agent_openrouter_completion_request",
        new=AsyncMock(return_value=deepseek_success),
    ) as mock_openrouter:
        response = await _handle_codex_auto_agent_alias_route(
            endpoint="/v1/responses",
            request=request,
            fastapi_response=MagicMock(spec=Response),
            user_api_key_dict=MagicMock(),
            prepared_request_body=body,
            target_url="https://chatgpt.com/backend-api/codex/responses",
            api_key=None,
            forward_headers=True,
        )

    assert response is deepseek_success
    mock_pass_through.assert_awaited_once()
    mock_openrouter.assert_awaited_once()
    assert mock_openrouter.await_args.kwargs["adapter_model"] == (
        "deepseek/deepseek-v4-flash"
    )
    deepseek_body = mock_openrouter.await_args.kwargs["request_body"]
    metadata = deepseek_body["litellm_metadata"]
    assert metadata["requested_model_alias"] == "aawm-read"
    assert metadata["codex_auto_agent_alias"] == "aawm-read"
    assert metadata["codex_auto_agent_selected_provider"] == "openrouter"
    first_attempt = metadata["codex_auto_agent_attempts"][0]
    assert first_attempt["status"] == "cooldown_set"
    assert first_attempt["error_class"] == "capacity_exhausted"
    assert "HIGH_DEMAND" in first_attempt["error_tokens"]
    assert metadata["codex_auto_agent_skipped_candidates"][0]["model"] == (
        "gpt-5.3-codex-spark"
    )


